var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"이번 경기는 장애물 달리기!","JPN":"次の試合は障害物競走！","ENG":"Our next game will be an obstacle race!","TWN":"這場比賽是障礙賽跑！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"홍팀 청팀의 대표 선수들이 트랙을 달리게 됩니다!","JPN":"赤組青組の代表選手がトラックを走ります！","ENG":"The representative players of the Red and Blue Teams will run along the tracks,","TWN":"紅隊藍隊的代表選手們在跑道上賽跑！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"각 팀은 상대 주전들을 자유롭게 방해할 수 있죠!","JPN":"各チームは相手の主力選手を自由に妨害できます！","ENG":"while the other players will interfere with the opposing team!","TWN":"各隊可以隨意妨礙對方的主力隊員！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"자! 그럼 각 팀의 대표 주자는 앞으로 나와 주세요!","JPN":"では！　各チームの代表選手は前に出てください！","ENG":"Now, representative players. Please come out.","TWN":"好了！請各隊的代表選手到前面來！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"흐흥. 역시 네가 나올 줄 알았어.","JPN":"ふーん、やっぱりあんたが出ると思った。","ENG":"Heh heh. I knew it'd be you.","TWN":"哼嗯，我就知道會是妳。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"진심으로 싸우기로 한 이 몸을 상대하게 되다니 좀 불쌍해지는걸?","JPN":"本気で戦うことにしたこの私が相手だなんて、ちょっと可哀そうね。","ENG":"You'd better watch out, because I've decided to take things seriously.","TWN":"接下來我要全力以赴了，遇上我算妳倒楣。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"방금 전 경기의 굴욕은 백 배로 갚아 주지!","JPN":"第一試合での屈辱は、百倍にして返してやる！","ENG":"I'll make you pay tenfold for the previous game!","TWN":"剛才那場比賽的恥辱，我會加倍還給妳！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"어라? 그 커다란 연필을 메고 있는 애는 어디 가고 네가 나온 거야?","JPN":"あれ？　あの大きな鉛筆を背負っている子はどこにいるの？","ENG":"Err? What happened to the girl with big pencils on her back?","TWN":"咦？怎麼又是妳呀？那個背著大鉛筆的人呢？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"점수가 큰 만큼 당연히 최고 실력자도 나올 줄 알았는데.","JPN":"今回もらえる点数は結構多いから、一番の実力者が出てくると思ったのに。","ENG":"Since a lot of points are at stake in this game, I thought your team would send out its best.","TWN":"按分數高低，不是應該最高實力者出來嗎？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"무, 무슨 뜻이야? 그거!","JPN":"ど、どういうこと！？","ENG":"W-what do you mean by that?","TWN":"妳，妳那是什麼意思？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"내가 그 야바위꾼보다 실력이 떨어진다는 말처럼 들리잖아!","JPN":"まるで私があのペテン師より実力が劣るみたいな言い方なんだけど？","ENG":"You think I'm not as good as that stupid clown?","TWN":"妳在說我的實力不如那個星星騙子！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"그럼 아니야? 방금 경기에서 꼬리를 하나도 못 모았잖아?","JPN":"違うの？　だってあなたはさっきの試合でしっぽを1つも取れなかったんだよね？","ENG":"What do you think? You didn't get any tails in the previous game.","TWN":"難道不是嗎？在剛才的比賽上，妳一條尾巴都沒拿到吧？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"하나도 못 모은 사람보다는 세 개나 모은 사람이 더 나은 것 같은데.","JPN":"1つも取れなかった人より、3つも集めた人の方が上でしょ。","ENG":"On the contrary, she got three.","TWN":"比起一條尾巴都沒拿到的人，拿到三條尾巴的人應該更厲害吧。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"시, 시끄러! 그건 머저리 같은 팀원들 탓이었어!","JPN":"う、うるさい！　あれはマヌケなチームメンバーのせいだから！","ENG":"Sh-shut up! That was because of my stupid teammates!","TWN":"妳，妳閉嘴！那還不是因為那些豬隊友！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"이번에야말로 내 진짜 실력을 보여 주지!","JPN":"今度こそ私の本当の実力を見せてやる！","ENG":"I'll show you what I really can do this time!","TWN":"這次我要讓妳見識一下我真正的實力！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"말리진 않을게. 어디 최선을 다해 봐.","JPN":"お好きにどうぞ。せいぜい頑張ってみて。","ENG":"Go ahead. No one's stopping ya.","TWN":"沒人攔妳，我拭目以待。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"이이익!","JPN":"キイイッ……！","ENG":"Eeeek!","TWN":"咿咿咿！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"아, 그래...... 그러고 보니 너 운동회에 참가하러 온 임시 편입생이라고 했지?","JPN":"あ、そうだ……そういえばあんた、運動会に参加するために来た臨時編入生って言ってたわね？","ENG":"Oh, right. Now that I think of it, you're just a temporary transfer student, here for the Field Day.","TWN":"啊，對了……妳是以臨時插班生的身份來參加運動會的吧？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"그렇다는 건 아카데미에서 정규 교육도 받지 못한 삼류 카운터란 뜻이네.","JPN":"ということはアカデミーで正規教育も受けていない三流カウンターってわけね。","ENG":"Which means, you're a third-rate Counter who's not good enough to deserve training at the Academy.","TWN":"那也就是說，妳不過是個沒接受學院正規教育的三流制裁者囉。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"보나마나 어딘가의 블랙기업에서 구르고 있는 용병 나부랭이겠지.","JPN":"どうせそこら辺のブラック企業でこき使われている下っ端傭兵なんでしょ。","ENG":"I bet you're a mercenary working for a sweatshop company somewhere.","TWN":"不用看也知道，妳肯定是在某家黑心企業裡被呼來喚去的傭兵小蝦米了。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"아하, 이거 갑자기 불쌍해지네?","JPN":"あーあ、可哀そうだからこれ以上言うのはやめとこうかな。","ENG":"Dang, I feel sorry for you all of a sudden.","TWN":"啊哈，突然覺得妳有點兒可憐呢。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"졸업만 하면 너 따위는 날 쳐다볼 수도 없는 사회적 격차가 날텐데 말이야!","JPN":"卒業さえすればあんたごときじゃ超えられない社会の壁ができるしね！","ENG":"Once I graduate, you won't ever see me again, because I'll be at the top while you're down in the muck!","TWN":"畢業以後，妳這種小角色跟我之間的社會差距就是一個天一個地！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"뭐, 틀린 말은 아니네.","JPN":"まあ、間違った話ではないわ。","ENG":"Well, you're right.","TWN":"嗯，妳說的沒錯。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"난 네 말대로 해서 관리국 정식 라이선스를 받은 프로 카운터거든.","JPN":"私はあなたの言うとおり、ブラック企業に勤めながら管理局の正式ライセンスを受けたプロカウンターなの。","ENG":"In the sense that I'm a pro Counter officially licensed by the Administration.","TWN":"的確是如妳所說，我是取得了管理局正式執照的職業制裁者。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"저, 정식 라이선스......?","JPN":"せ、正式ライセンス……？","ENG":"O-officially licensed?","TWN":"正，正式執照……？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"말도 안 돼...... 그건 아카데미에서도 나 같은 엘리트나 노려 볼 수 있는 건데?","JPN":"ありえない……それはアカデミーの私みたいなエリートでも一部しかもらえないものなのに！？","ENG":"No way! Even the Academy's elite students like me have to work hard for that.","TWN":"不可能……那可是學院裡只有像我這樣的精英才有可能拿到的？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"거짓말! 거짓말이야! 너 따위가 정식 라이선스를 가지고 있을 리 없어!","JPN":"嘘！　嘘よ！　あんたごときが正式ライセンスを持っているはずがないわ！","ENG":"You're lying! Liar! There's no way someone like you has an official license!","TWN":"妳撒謊！妳撒謊！妳這種小角色不可能持有正式執照！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"......응?","JPN":"……うん？","ENG":"Mm?","TWN":"……嗯？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"혹시 나한테 하는 말이야?","JPN":"今私に話しかけてるの？","ENG":"Are you talking to me?","TWN":"妳是在跟我說話嗎？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"정식 라이선스도 없는 <color=#ffd34c>아. 마. 추. 어.</color> 씨 말이라 잘 안 들리는데.","JPN":"正式ライセンスすら持っていない<color=#ffd34c>ア・マ・チュ・ア</color>の話は聞く価値がないから声も聞こえないわ。","ENG":"I can't hear you, because you're an <color=#ffd34c>A. M. A. T. E. U. R.</color> who doesn't even have an official license.","TWN":"沒有正式執照的<color=#ffd34c>業.餘.</color>選手還真是聽不懂人話呢。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"으아아악!! 짜증나! 뭐 저런 게 다 있어?!","JPN":"もおおおーっ！　ムカつく！　何なのあいつは！？","ENG":"Gaaaah! How can you be so annoying?","TWN":"呃啊啊啊！！真討厭！怎麼會有妳這種人？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"두고 봐, 너! 이번 경기에서 고개도 못 들고 다닐 만큼 확실하게 밟아 줄 테니까!","JPN":"今に見てなさい！　今回の試合で確実にそのデカい鼻をへし折ってやるから！","ENG":"You just wait and see! I'll crush you so hard that you won't even show up for the next game!","TWN":"妳等著！這場比賽我一定要完勝妳，我要讓妳永遠抬不起頭！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"하아...... 너무 재미있잖아.","JPN":"ああ……楽しすぎる。","ENG":"Gosh, this is way too fun.","TWN":"哈啊……太有意思了。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"이러다 나쁜 버릇이 들 것 같아......","JPN":"これは癖になりそう……","ENG":"It's going to spoil me rotten...","TWN":"這樣下去我的壞習慣又蠢蠢欲動了……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"하지만 어쩔 수 없지. 이 정도로 반응이 좋은 녀석은 미나 이후로 처음인걸.","JPN":"でもしょうがないよね。煽りにこんな面白い反応をしてくれるのはミナ以来だから。","ENG":"But I can't help it. I've never met anyone who's so responsive, ever since Mina.","TWN":"不過沒辦法啊，除了米娜，我還是第一次遇到這麼好玩的傢伙。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"그럼! 다들 출발선에 섰나요?","JPN":"さて！　みんなスタートラインに立ちましたか？","ENG":"Now, is everyone at the starting line?","TWN":"好了！大家都站到起跑線前了嗎？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"두번째 경기! 시작!!","JPN":"第二試合！　スタート！！","ENG":"Let's start the second game!","TWN":"第二場比賽！開始！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};